      /* ---- council ---- */
      council_source_intro: '<strong>出典：</strong>小牧市議会だより No.214（令和8年5月発行）をもとに作成しています。正確な情報は小牧市議会だより No.214（令和8年5月発行）でご確認ください。',
      council_overview_title: '📋 令和8年 第1回定例会の概要',
