      meta_title_faq: 'Câu hỏi Thường gặp – Tái cơ cấu Trường học phía Đông Komaki',
      meta_title_voices: 'Tiếng nói Cộng đồng – Tái cơ cấu Trường học phía Đông Komaki',
      meta_title_council: 'Nghị quyết Hội đồng – Tái cơ cấu Trường học phía Đông Komaki',
      meta_title_map: 'Vị trí Trường học (Bản đồ) – Tái cơ cấu Trường học phía Đông Komaki',
      meta_desc_index: 'Trang thông tin cộng đồng cung cấp thông tin dễ hiểu về kế hoạch tái cơ cấu trường học phía Đông Komaki (Shinooka), dự kiến thực hiện năm học 2027.',
      meta_desc_about: 'Thông tin chi tiết về kế hoạch tái cơ cấu 5 tiểu học và 3 THCS thành 4 trường trong năm học 2027 — lý do, nội dung và kế hoạch đi lại.',
      meta_desc_schedule: 'Tóm tắt lịch trình của kế hoạch tái cơ cấu, bao gồm các buổi thông báo, trao đổi ý kiến và ngày dự kiến thực hiện.',
      meta_desc_faq: 'Các câu hỏi thường gặp và câu trả lời về kế hoạch tái cơ cấu trường học, bao gồm đi lại, cơ sở vật chất, lịch trình và nhiều hơn nữa.',
      meta_desc_voices: 'Tổng hợp các ý kiến ủng hộ, phản đối và trung lập từ cư dân, phụ huynh và chuyên gia về kế hoạch tái cơ cấu trường học.',
      meta_desc_council: 'Tóm tắt rõ ràng các nghị quyết hội đồng tại Phiên họp thường kỳ lần 1 năm 2026 (tháng 3), bao gồm việc sửa đổi quy định thành lập trường.',
      meta_desc_map: 'Xem vị trí 8 trường hiện tại và 4 trường sau khi tái cơ cấu trên Google Maps.',
