      stat_class_label: 'Lahat ng elementarya &amp; Shinooka JHS inaasahang<br>magkakaroon ng 1 klase bawat antas',
      stat_reorg_label: 'Yugto 1 ng Muling Pagsasaayos (Nakatakda)',

      stat_num_youth: 'Mas sa kalahati',
