      sched_desc15: '<strong>Período de Comentarios Públicos</strong><br>55 envíos recibidos (39 correo electrónico, 13 fax, 1 correo postal, 2 en persona). La ciudad publicó respuestas y el plan revisado.',
      sched_desc16: '<strong>Encuesta sobre el Nombre de la Nueva Escuela</strong> (en línea)',
