      sched_h4_other_2025: '● Kegiatan Lainnya (2025)',
      sched_desc1: '<strong>Pertemuan Diskusi Sekolah Distrik Shinooka ke-1</strong> (Aula Pusat Komunitas Timur, kapasitas 300)<br>Topik: Masalah seputar pendidikan sekolah di distrik Shinooka',
      sched_desc2: '<strong>Pertemuan Diskusi Sekolah Distrik Shinooka ke-2</strong> (Aula Pusat Komunitas Timur)<br>Topik: Tinjauan pertemuan ke-1, rancangan rencana reorganisasi distrik Shinooka',
      sched_desc3: '<strong>Pertemuan Diskusi Sekolah Distrik Shinooka ke-3</strong> (Aula Pusat Komunitas Timur)<br>Topik: Tinjauan pertemuan ke-2, distrik sekolah &amp; bus sekolah, arah ke depan',
      sched_desc4: '<strong>Pertemuan Diskusi Sekolah Distrik Shinooka ke-4</strong> (Aula Pusat Komunitas Timur)<br>Topik: Tinjauan pertemuan ke-3, hasil pertukaran pendapat orang tua &amp; sosialisasi komunitas, tinjauan rancangan rencana reorganisasi',
      sched_desc5: '<strong>Laporan kepada Perwakilan Dewan Komunitas</strong> (Balai Kota Komaki)',
      sched_desc6: '<strong>Laporan Asosiasi Warga Distrik Shinooka (ke-1)</strong> (Pusat Komunitas Timur)',
      sched_desc7: '<strong>Survei Siswa</strong> (online)',
      sched_desc8: '<strong>Survei Orang Tua</strong> (online)',
      sched_desc9: '<strong>Sosialisasi Shiroyama 3 &amp; 4-chome</strong> (Balai Komunitas Shiroyama)',
      sched_desc10: '<strong>Pertemuan Pertukaran Pendapat Orang Tua ke-1</strong> (Pusat Komunitas Timur)',
      sched_desc11: '<strong>Pertemuan Pertukaran Pendapat Orang Tua ke-2 &amp; ke-3</strong> (Pusat Komunitas Timur)',
      sched_desc12: '<strong>Sosialisasi Komunitas</strong> (Pusat Komunitas Timur)',
